import AsyncStorage from '@react-native-async-storage/async-storage';
import { Platform } from 'react-native';

const AUTH_TOKEN_KEY = 'auth_token';
const USER_DATA_KEY = 'user_data';

export const authService = {
  async login(credentials) {
    try {
      const response = await fetch('https://your-api.com/login', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(credentials),
      });

      const data = await response.json();

      if (!response.ok) {
        throw new Error(data.message || 'Login failed');
      }

      await AsyncStorage.multiSet([
        [AUTH_TOKEN_KEY, data.token],
        [USER_DATA_KEY, JSON.stringify(data.user)],
      ]);

      return data;
    } catch (error) {
      throw error;
    }
  },

  async logout() {
    try {
      await AsyncStorage.multiRemove([AUTH_TOKEN_KEY, USER_DATA_KEY]);
    } catch (error) {
      console.error('Logout error:', error);
    }
  },

  async getAuthState() {
    try {
      const [token, userData] = await AsyncStorage.multiGet([
        AUTH_TOKEN_KEY,
        USER_DATA_KEY,
      ]);

      const tokenValue = token[1];
      const userDataValue = userData[1];

      if (tokenValue && userDataValue) {
        return {
          isAuthenticated: true,
          token: tokenValue,
          user: JSON.parse(userDataValue),
        };
      }

      return {
        isAuthenticated: false,
        token: null,
        user: null,
      };
    } catch (error) {
      console.error('Auth state error:', error);
      return {
        isAuthenticated: false,
        token: null,
        user: null,
      };
    }
  },

  async refreshToken() {
    try {
      const token = await AsyncStorage.getItem(AUTH_TOKEN_KEY);
      
      if (!token) {
        throw new Error('No token found');
      }

      const response = await fetch('https://your-api.com/refresh', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}`,
        },
      });

      const data = await response.json();

      if (!response.ok) {
        throw new Error(data.message || 'Token refresh failed');
      }

      await AsyncStorage.setItem(AUTH_TOKEN_KEY, data.token);
      return data.token;
    } catch (error) {
      await this.logout();
      throw error;
    }
  },

  async getAuthToken() {
    try {
      const token = await AsyncStorage.getItem(AUTH_TOKEN_KEY);
      return token;
    } catch (error) {
      console.error('Token retrieval error:', error);
      return null;
    }
  },

  async getUserData() {
    try {
      const userData = await AsyncStorage.getItem(USER_DATA_KEY);
      return userData ? JSON.parse(userData) : null;
    } catch (error) {
      console.error('User data retrieval error:', error);
      return null;
    }
  },
};

export const secureFetch = async (url, options = {}) => {
  try {
    const token = await authService.getAuthToken();
    
    const config = {
      ...options,
      headers: {
        'Content-Type': 'application/json',
        ...options.headers,
        ...(token && { Authorization: `Bearer ${token}` }),
      },
    };

    let response = await fetch(url, config);

    if (response.status === 401) {
      const newToken = await authService.refreshToken();
      config.headers.Authorization = `Bearer ${newToken}`;
      response = await fetch(url, config);
    }

    if (!response.ok) {
      const errorData = await response.json();
      throw new Error(errorData.message || 'Request failed');
    }

    return response.json();
  } catch (error) {
    throw error;
  }
};